// src/domain/withdrawals.ts
function toWithdrawalStatusWire(status) {
  switch (status) {
    case "accepted":
      return "ACCEPTED";
    case "transferred":
      return "TRANSFERRED";
    default:
      return status.toUpperCase();
  }
}

